/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(VendPackingSlipJournal, ETGBonDePaimentReport), FormControlEventType::Clicked)]
public static void ETGBonDePaimentReport_OnClicked(FormControl sender, FormControlEventArgs e)
{
    VendPackingSlipJour         VendPackingSlipJour;
    SrsReportRunController      reportRunController;
    SrsReportRunImpl            srsReportRun;
    ETGBonDePaimentCacaoContract dataContract;
    Args args = new args();


    reportRunController = new SrsReportRunController();


    FormButtonControl callerButton = sender as FormButtonControl;
    //Retrieves the button that we're reacting to
    FormRun form = callerButton.formRun(); //Gets the running SalesEditLines form

    //Get the salesId that was selected in the SalesEditLines form
    FormDataSource VendPackingSlipJour_ds = form.dataSource(formDataSourceStr(VendPackingSlipJournal, VendPackingSlipJour)) as FormDataSource;
    VendPackingSlipJour VendPackingSlipJourloc = VendPackingSlipJour_ds.cursor();
    //SalesTable salesTable=salesParmTable.salesTable();


    dataContract = new  ETGBonDePaimentCacaoContract();
    reportRunController.parmReportName(ssrsReportStr(ETGBonDePaiment,ETGBonDePaiment));

    reportRunController.parmShowDialog(false);
    dataContract = reportRunController.parmReportContract().parmRdpContract() as ETGBonDePaimentCacaoContract;
    dataContract.parmRecId(VendPackingSlipJourloc.RecId);
    srsReportRun = reportRunController.parmReportRun() as SrsReportRunImpl;
    reportRunController.parmReportRun(srsReportRun);
    reportRunController.parmDialogCaption("BON DE PAIEMENT CACAO Report");
    reportRunController.parmReportContract().parmPrintSettings().printMediumType(SRSPrintMediumType::Screen);
    reportRunController.startOperation();

}

